VALUES
  ('heelevel3-6f0ba476-moex-00132', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-113-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '某公司在甲銀行之現金活期存款為$750,000，其中$180,000 為去年向銀行借款時，銀行所要求之 補償性存款。此外，在乙銀行之存款帳戶則為透支$20,000。請問該公司於資產負債表中應報導之 現金金額為多少？', '["$550,000", "$570,000", "$730,000", "$850,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "318", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00133', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-113-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '關於不動產、廠房及設備，下列正確的敘述共有幾項？', '["採成本模式時，資產發生價值減損後仍須提列折舊", "評估資產減損時，可回收金額係指資產的公允價值減處分成本後餘額與使用價值，二者較高者", "採重估價模式時，仍須提列折舊與攤銷", "如符合分類為待出售條件之資產，應停止提列折舊"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "318", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00134', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-113-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司於X4年7月1日與乙公司完成一項資產交易協議，甲公司該項換出資產X1年1月1日 原始取得成本為 $600,000，無殘值，耐用年限5年。交換日甲公司資產之公允價值為$200,000， 並另向乙公司收取現金$5,000。則有關該交換交易會計處理之敘述，何者錯誤？', '["若此筆交易具商業實質，則甲公司應認列換入資產價值為$195,000", "若此筆交易具商業實質，則甲公司應認處分利益$20,000", "若此筆交易不具商業實質，則甲公司應認列換入資產價值為$185,000", "若此筆交易不具商業實質，則甲公司毋須認列任何處分利益"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "318", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00135', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-113-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司紡織部門為一現金產生單位，部門內有A、B、C機器及商譽，本年年底之帳面金額分別為 $20,000、$30,000、$40,000及$10,000。因所屬產業環境變動，本年底該部門發生減損跡象，經估 計其可回收金額為$63,000，請問C機器應分攤之減損損失應為多少？', '["$12,000", "$14,800", "$9,000", "$16,444"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "318", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00136', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-113-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年10月1日賒銷商品$150,000，付款條件為2/10，1/20，n/30；X1年10月8日顧 客因商品瑕疵退回$20,000，並於隔日收到部分貨款之現金為$58,800，其餘貨款於 10 月 19 日收 現。請問該公司對於該批賒銷商品之總收現金額為多少？', '["$128,800", "$128,100", "$125,800", "$148,800"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "318", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00137', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-113-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司本年度的銷貨收入$500,000，銷貨成本$320,000，利息收入$20,000，應收帳款增加$20,000， 應付帳款減少$30,000，應收利息減少$5,000，該公司將利息收入列為營業活動項目。試求直接法 下營業活動之現金流量為何？', '["$155,000", "$195,000", "$215,000", "$255,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "318", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00138', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-113-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'essay', '甲有 A 屋一間，因已閒置一年，決定出租。乙見 A 屋地段佳，甚為喜
歡，而與甲簽訂租賃契約承租 A屋，雙方約定租賃期間自民國 112 年 7
月 1 日起至民國 114 年 6 月 30 日止，乙當場支付三個月租金總額之押
租金予甲，並於隔日搬入居住。甲於民國113 年2 月 1 日將 A屋出售於
丙，並辦理所有權移轉登記完畢，丙以其為 A屋所有權人且未出租於乙
為由，要求乙搬離，乙則以其係向甲承租為由斷然拒絕，何人之主張有
理由？若丙未要求乙搬離，當租賃期間屆滿，乙搬離時，可否請求丙返
還押租金？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "318", "s": "1005", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00139', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-113-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'essay', '甲、乙、丙共有A地一筆，應有部分各為三分之一。於民國 112年 9 月
起，丁未得共有人之同意，擅自於該地劃設三十個停車位，並以每個月
租金新臺幣五千元對外出租，三十個車位當即全數出租。甲於民國 113
年 3 月發現 A 地為丁所占用，甲可否要求丁將 A 地及占用 A 地期間所
收取租金返還於自己？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "318", "s": "1005", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00140', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-113-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '未保留胎兒應繼分之遺產協議分割行為，其效力為何？', '["有效", "無效", "得撤銷", "效力未定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "318", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00141', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-113-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '甲將一平板電腦借乙使用，乙使用時，好友丙見到，非常羨慕，表示願以高價購買之，乙見機不 可失，遂以自己名義賣與丙，並將該平板電腦交付於丙。有關乙、丙間之法律行為，下列敘述， 何者正確？', '["債權行為與物權行為均無效", "債權行為與物權行為均效力未定", "債權行為效力未定，物權行為無效", "債權行為有效，物權行為效力未定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "318", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL)
